import { Component } from '@angular/core';
import { Item } from 'src/app/models/item';
import { DataService } from 'src/app/services/data.service';

@Component({
  selector: 'app-items',
  templateUrl: './items.component.html',
  styleUrls: ['./items.component.css']
})
export class ItemsComponent {
  item: Item[] = [];
  constructor(
    private svc:DataService
  ) { }

  ngOnInit() {
    this.svc.getItems().subscribe(x => {
      this.item = x;
    })
  }
}
<div class="row">
  <div class="col d-flex">
    <h2 class="display-5 mb-2">Item List</h2>
    <a
      class="btn btn-outline-primary justify-content-end mb-2"
      [routerLink]="['/add-items']"
      >Add new items</a
    >
    <table class="table table-bordered table-striped table-sm table-hover">
      <thead>
        <tr>
          <th>Item Id</th>
          <th>Item Name</th>
          <th>Item Price</th>
          <th>Item Stock</th>
        </tr>
      </thead>
      <tbody>
        <tr *ngFor="let i of item">
          <td>{{ i.itemId }}</td>
          <td>{{ i.itemName }}</td>
          <td>{{ i.unitPrice }}</td>
          <td>{{ i.stock }}</td>
        </tr>
      </tbody>
    </table>
  </div>
</div>
